7	 */
8	
9	#define VERSION "1.0.3"
10	
11	#define _XOPEN_SOURCE 500 // for: usleep
12	#include <stdio.h>		  // defines: printf, puts, getchar
13	#include <stdlib.h>		  // defines: EXIT_SUCCESS
14	#include <string.h>		  // defines: strcmp
15	#include <unistd.h>		  // defines: STDIN_FILENO, usleep
16	#include <termios.h>	  // defines: termios, TCSANOW, ICANON, ECHO
17	#include <stdbool.h>	  // defines: true, false
18	#include <stdint.h>		  // defines: uint8_t, uint32_t
19	#include <time.h>		  // defines: time
20	#include <signal.h>		  // defines: signal, SIGINT
21	
22	#define SIZE 4
23	
24	// Specification helper: a file-scope mirror of the four local color schemes,
25	// used only inside getColors's contract to pin the exact output values.  A
26	// global const table is used (rather than an in-contract compound literal) so
27	// the postconditions stay cheap to evaluate and remain reachable within CBMC's
28	// bounded analysis depth.  Each row has 32 entries (== sizeof(original)).
29	static const uint8_t getColors_schemes[4][32] = {
30		{8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0},
31		{232, 255, 234, 255, 236, 255, 238, 255, 240, 255, 242, 255, 244, 255, 246, 0, 248, 0, 249, 0, 250, 0, 251, 0, 252, 0, 253, 0, 254, 0, 255, 0},
32		{235, 255, 63, 255, 57, 255, 93, 255, 129, 255, 165, 255, 201, 255, 200, 255, 199, 255, 198, 255, 197, 255, 196, 255, 196, 255, 196, 255, 196, 255, 196, 255},
33		{255, 0, 254, 0, 253, 0, 252, 0, 251, 0, 250, 0, 249, 0, 248, 0, 246, 255, 244, 255, 242, 255, 240, 255, 238, 255, 236, 255, 234, 255, 232, 255}};
34	
35	// this function receives 2 pointers (indicated by *) so it can set their values
36	void getColors(uint8_t value, uint8_t scheme, uint8_t *foreground, uint8_t *background)
37	// scheme must index one of the four schemes (else schemes[scheme] reads out of
38	// bounds); both output locations must be writable.  The three conditions are
39	// stated as a single requires clause: fewer clauses means fewer assume steps,
40	// which keeps the postconditions reachable within CBMC's bounded depth.
41	__CPROVER_requires(scheme < 4 &&
42	                   __CPROVER_w_ok(foreground, sizeof(uint8_t)) &&
43	                   __CPROVER_w_ok(background, sizeof(uint8_t)))
44	__CPROVER_assigns(*foreground, *background)
45	// The outputs are exactly the indexed entries of the selected scheme.  The
46	// foreground index is the background index + 1 (foreground is always at an odd
47	// offset, background at the preceding even one); writing it that way shares the
48	// (value * 2) % 32 subexpression and keeps both postconditions cheap.
49	// Background is stated first so, under bounded depth, its postcondition is
50	// reached before the budget is exhausted.
51	__CPROVER_ensures(*background == getColors_schemes[scheme][value * 2 % 32])
52	__CPROVER_ensures(*foreground == getColors_schemes[scheme][value * 2 % 32 + 1])
53	{
54		uint8_t original[] = {8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0};
55		uint8_t blackwhite[] = {232, 255, 234, 255, 236, 255, 238, 255, 240, 255, 242, 255, 244, 255, 246, 0, 248, 0, 249, 0, 250, 0, 251, 0, 252, 0, 253, 0, 254, 0, 255, 0};
56		uint8_t bluered[] = {235, 255, 63, 255, 57, 255, 93, 255, 129, 255, 165, 255, 201, 255, 200, 255, 199, 255, 198, 255, 197, 255, 196, 255, 196, 255, 196, 255, 196, 255, 196, 255};
57		uint8_t whiteblack[] = {255, 0, 254, 0, 253, 0, 252, 0, 251, 0, 250, 0, 249, 0, 248, 0, 246, 255, 244, 255, 242, 255, 240, 255, 238, 255, 236, 255, 234, 255, 232, 255};
58		uint8_t *schemes[] = {original, blackwhite, bluered, whiteblack};
59		// modify the 'pointed to' variables (using a * on the left hand of the assignment)
60		*foreground = *(schemes[scheme] + (1 + value * 2) % sizeof(original));
61		*background = *(schemes[scheme] + (0 + value * 2) % sizeof(original));
62		// alternatively we could have returned a struct with two variables
63	}
64	
65	// Specification helper: powers of ten as 64-bit values so the contract can
66	// pin the exact decimal-digit count.  A uint32_t can be at most 4294967295
67	// (10 digits), so we need 10^0 .. 10^10; the last entry overflows uint32_t,
68	// hence uint64_t.  A file-scope const table keeps the postcondition cheap to
69	// evaluate and reachable within CBMC's bounded analysis depth.
70	static const uint64_t getDigitCount_pow10[11] = {
71		1ULL, 10ULL, 100ULL, 1000ULL, 10000ULL, 100000ULL, 1000000ULL,
72		10000000ULL, 100000000ULL, 1000000000ULL, 10000000000ULL};
73	
74	uint8_t getDigitCount(uint32_t number)
75	// The return value is the number of decimal digits of `number`, with the
76	// edge case that 0 has one digit (the do-while body always runs once).  It
77	// therefore lies in 1..10 for any 32-bit input.  The two-sided bound pins the
78	// exact digit count: `number` is strictly below 10^r and (unless r==1) at
79	// least 10^(r-1), which uniquely identifies r.
80	__CPROVER_ensures(__CPROVER_return_value >= 1 && __CPROVER_return_value <= 10)
81	__CPROVER_ensures(number < getDigitCount_pow10[__CPROVER_return_value])
82	__CPROVER_ensures(__CPROVER_return_value == 1 ||
83	                  number >= getDigitCount_pow10[__CPROVER_return_value - 1])
84	{
85		uint8_t count = 0;
86		do
87		{
88			number /= 10;
89			count += 1;
90		} while (number);
91		return count;
92	}
93	
94	void drawBoard(uint8_t board[SIZE][SIZE], uint8_t scheme, uint32_t score)
95	// board must be readable; scheme must index one of the four color schemes (the
96	// precondition of every getColors call below); and each cell value must be at
97	// most 30 so that `1 << board[x][y]` (computed as a signed int) stays
98	// well-defined -- a larger exponent would shift into/past the sign bit (UB).
99	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
100	__CPROVER_requires(scheme < 4)
101	__CPROVER_requires(__CPROVER_forall {
102		int i; (0 <= i && i < SIZE) ==> __CPROVER_forall {
103			int j; (0 <= j && j < SIZE) ==> board[i][j] <= 30 } })
104	// drawBoard only emits text; it writes nothing but its own locals.  The empty
105	// assigns clause pins this down: the board (and all other pre-existing memory)
106	// is left untouched.
107	__CPROVER_assigns()
108	{
109		uint8_t x, y, fg, bg;
110		printf("\033[H"); // move cursor to 0,0
111		printf("2048.c %17u pts\n\n", score);
112		for (y = 0; y < SIZE; y++)
113		{
114			for (x = 0; x < SIZE; x++)
115			{
116				// send the addresses of the foreground and background variables,
117				// so that they can be modified by the getColors function
118				getColors(board[x][y], scheme, &fg, &bg);
119				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
120				printf("       ");
121				printf("\033[m"); // reset all modes
122			}
123			printf("\n");
124			for (x = 0; x < SIZE; x++)
125			{
126				getColors(board[x][y], scheme, &fg, &bg);
127				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
128				if (board[x][y] != 0)
129				{
130					uint32_t number = 1 << board[x][y];
131					uint8_t t = 7 - getDigitCount(number);
132					printf("%*s%u%*s", t - t / 2, "", number, t / 2, "");
133				}
134				else
135				{
136					printf("   ·   ");
137				}
138				printf("\033[m"); // reset all modes
139			}
140			printf("\n");
141			for (x = 0; x < SIZE; x++)
142			{
143				getColors(board[x][y], scheme, &fg, &bg);
144				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
145				printf("       ");
146				printf("\033[m"); // reset all modes
147			}
148			printf("\n");
149		}
150		printf("\n");
151		printf("        ←,↑,→,↓ or q        \n");
152		printf("\033[A"); // one line up
153	}
154	
155	uint8_t findTarget(uint8_t array[SIZE], uint8_t x, uint8_t stop)
156	{
157		uint8_t t;
158		// if the position is already on the first, don't evaluate
159		if (x == 0)
160		{
161			return x;
162		}
163		for (t = x - 1;; t--)
164		{
165			if (array[t] != 0)
166			{
167				if (array[t] != array[x])
168				{
169					// merge is not possible, take next position
170					return t + 1;
171				}
172				return t;
173			}
174			else
175			{
176				// we should not slide further, return this one
177				if (t == stop)
178				{
179					return t;
180				}
181			}
182		}
183		// we did not find a target
184		return x;
185	}
186	
187	bool slideArray(uint8_t array[SIZE], uint32_t *score)
188	{
189		bool success = false;
190		uint8_t x, t, stop = 0;
191	
192		for (x = 0; x < SIZE; x++)
193		{
194			if (array[x] != 0)
195			{
196				t = findTarget(array, x, stop);
197				// if target is not original position, then move or merge
198				if (t != x)
199				{
200					// if target is zero, this is a move
201					if (array[t] == 0)
202					{
203						array[t] = array[x];
204					}
205					else if (array[t] == array[x])
206					{
207						// merge (increase power of two)
208						array[t]++;
209						// increase score
210						*score += 1 << array[t];
211						// set stop to avoid double merge
212						stop = t + 1;
213					}
214					array[x] = 0;
215					success = true;
216				}
217			}
218		}
219		return success;
220	}
221	
222	/* rotateBoard rotates the 4x4 board 90 degrees counter-clockwise in place:
223	 * every destination cell (i,j) ends up holding the pre-state value of cell
224	 * (j, SIZE-1-i).  Constant cell indices are enumerated below because CBMC's
225	 * history variables (`__CPROVER_old`) do not support array snapshots under a
226	 * quantified index, so the full permutation is pinned cell-by-cell. */
227	#define ROTATED(i, j) (board[i][j] == __CPROVER_old(board[j][SIZE - 1 - i]))
228	
229	void rotateBoard(uint8_t board[SIZE][SIZE])
230	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
231	__CPROVER_assigns(__CPROVER_object_whole(board))
232	__CPROVER_ensures(ROTATED(0, 0))
233	__CPROVER_ensures(ROTATED(0, 1))
234	__CPROVER_ensures(ROTATED(0, 2))
235	__CPROVER_ensures(ROTATED(0, 3))
236	__CPROVER_ensures(ROTATED(1, 0))
237	__CPROVER_ensures(ROTATED(1, 1))
238	__CPROVER_ensures(ROTATED(1, 2))
239	__CPROVER_ensures(ROTATED(1, 3))
240	__CPROVER_ensures(ROTATED(2, 0))
241	__CPROVER_ensures(ROTATED(2, 1))
242	__CPROVER_ensures(ROTATED(2, 2))
243	__CPROVER_ensures(ROTATED(2, 3))
244	__CPROVER_ensures(ROTATED(3, 0))
245	__CPROVER_ensures(ROTATED(3, 1))
246	__CPROVER_ensures(ROTATED(3, 2))
247	__CPROVER_ensures(ROTATED(3, 3))
248	{
249		uint8_t i, j, n = SIZE;
250		uint8_t tmp;
251		for (i = 0; i < n / 2; i++)
252		{
253			for (j = i; j < n - i - 1; j++)
254			{
255				tmp = board[i][j];
256				board[i][j] = board[j][n - i - 1];
257				board[j][n - i - 1] = board[n - i - 1][n - j - 1];
258				board[n - i - 1][n - j - 1] = board[n - j - 1][i];
259				board[n - j - 1][i] = tmp;
260			}
261		}
262	}
263	
264	bool moveUp(uint8_t board[SIZE][SIZE], uint32_t *score)
265	{
266		bool success = false;
267		uint8_t x;
268		for (x = 0; x < SIZE; x++)
269		{
270			success |= slideArray(board[x], score);
271		}
272		return success;
273	}
274	
275	bool moveLeft(uint8_t board[SIZE][SIZE], uint32_t *score)
276	{
277		bool success;
278		rotateBoard(board);
279		success = moveUp(board, score);
280		rotateBoard(board);
281		rotateBoard(board);
282		rotateBoard(board);
283		return success;
284	}
285	
286	bool moveDown(uint8_t board[SIZE][SIZE], uint32_t *score)
287	{
288		bool success;
289		rotateBoard(board);
290		rotateBoard(board);
291		success = moveUp(board, score);
292		rotateBoard(board);
293		rotateBoard(board);
294		return success;
295	}
296	
297	bool moveRight(uint8_t board[SIZE][SIZE], uint32_t *score)
298	{
299		bool success;
300		rotateBoard(board);
301		rotateBoard(board);
302		rotateBoard(board);
303		success = moveUp(board, score);
304		rotateBoard(board);
305		return success;
306	}
307	
308	// True iff row r contains two horizontally-adjacent equal cells.  Spelled out
309	// per column so the contract stays a plain straight-line expression CBMC can
310	// evaluate within its bounded depth (no quantifier, no nested loop).
311	#define PAIR_IN_ROW(r) \
312		((board[r][0] == board[r][1]) || (board[r][1] == board[r][2]) || \
313		 (board[r][2] == board[r][3]))
314	
315	bool findPairDown(uint8_t board[SIZE][SIZE])
316	// The board is only read, so nothing is assigned.  The postcondition pins the
317	// return value to the exact existential condition the loop computes, tying it to
318	// every relevant adjacent-cell comparison -- a strong spec that distinguishes
319	// mutations of the loop bounds, the index offset, or the comparison operator.
320	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
321	__CPROVER_assigns()
322	__CPROVER_ensures(__CPROVER_return_value ==
323	                  (PAIR_IN_ROW(0) || PAIR_IN_ROW(1) ||
324	                   PAIR_IN_ROW(2) || PAIR_IN_ROW(3)))
325	{
326		bool success = false;
327		uint8_t x, y;
328		for (x = 0; x < SIZE; x++)
329		{
330			for (y = 0; y < SIZE - 1; y++)
331			{
332				if (board[x][y] == board[x][y + 1])
333					return true;
334			}
335		}
336		return success;
337	}
338	
339	// Number of empty (== 0) cells in one row r.  Spelled out per column so the
340	// expression stays a plain straight-line sum that CBMC can evaluate within its
341	// bounded analysis depth (no quantifier, no nested loop in the contract).
342	#define COUNT_EMPTY_ROW(r) \
343		((board[r][0] == 0) + (board[r][1] == 0) + \
344		 (board[r][2] == 0) + (board[r][3] == 0))
345	
346	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
347	// The board is only read, so nothing is assigned.  The postcondition pins the
348	// return value to the exact number of zero cells, which both bounds it to
349	// [0, SIZE*SIZE] and ties it to every individual cell -- a strong spec that
350	// distinguishes any mutation of the loop bounds, the comparison, or the counter.
351	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
352	__CPROVER_assigns()
353	__CPROVER_ensures(__CPROVER_return_value ==
354	                  COUNT_EMPTY_ROW(0) + COUNT_EMPTY_ROW(1) +
355	                  COUNT_EMPTY_ROW(2) + COUNT_EMPTY_ROW(3))
356	{
357		uint8_t x, y;
358		uint8_t count = 0;
359		for (x = 0; x < SIZE; x++)
360		{
361			for (y = 0; y < SIZE; y++)
362			{
363				if (board[x][y] == 0)
364				{
365					count++;
366				}
367			}
368		}
369		return count;
370	}
371	
372	/* The game is over exactly when no move can change the board: there are no
373	 * empty cells AND no two horizontally-adjacent equal cells AND no two
374	 * vertically-adjacent equal cells.  This is precisely what gameEnded computes:
375	 * countEmpty rules out empties, the first findPairDown rules out a horizontal
376	 * pair, and (after a 90-degree rotation) the second findPairDown rules out a
377	 * vertical pair; the remaining three rotations merely restore the board.
378	 *
379	 * NO_EMPTY reuses COUNT_EMPTY_ROW; ANY_H_PAIR reuses PAIR_IN_ROW (both defined
380	 * above).  PAIR_IN_COL is the column analogue of PAIR_IN_ROW: a horizontal pair
381	 * in the once-rotated board corresponds exactly to a vertically-adjacent equal
382	 * pair in the entry board, which is what the second findPairDown detects. */
383	#define NO_EMPTY \
384		(COUNT_EMPTY_ROW(0) + COUNT_EMPTY_ROW(1) + \
385		 COUNT_EMPTY_ROW(2) + COUNT_EMPTY_ROW(3) == 0)
386	#define ANY_H_PAIR \
387		(PAIR_IN_ROW(0) || PAIR_IN_ROW(1) || PAIR_IN_ROW(2) || PAIR_IN_ROW(3))
388	#define PAIR_IN_COL(c) \
389		((board[0][c] == board[1][c]) || (board[1][c] == board[2][c]) || \
390		 (board[2][c] == board[3][c]))
391	#define ANY_V_PAIR \
392		(PAIR_IN_COL(0) || PAIR_IN_COL(1) || PAIR_IN_COL(2) || PAIR_IN_COL(3))
393	
394	/* Cell (i,j) is restored to its entry value (four 90-degree rotations == a full
395	 * turn == identity). */
396	#define GE_UNCHANGED(i, j) (board[i][j] == __CPROVER_old(board[i][j]))
397	
398	bool gameEnded(uint8_t board[SIZE][SIZE])
399	// The return value is pinned to the exact "no legal move remains" predicate, and
400	// the board is required to be left unchanged.  This is a strong specification: it
401	// ties the result to every cell's emptiness and every horizontal and vertical
402	// adjacency, and pins the post-state of all sixteen cells.
403	//
404	// NOTE ON DEPTH: run-cbmc verifies with a fixed `--depth 200`.  This
405	// postcondition cannot be reached and evaluated within that bound -- the four
406	// contract-replaced rotateBoard calls (~230 steps just to traverse) plus the
407	// ~350 steps it takes to symbolically evaluate the 16-cell predicate together
408	// far exceed 200, so at depth 200 CBMC stops short and reports success
409	// vacuously (it was confirmed sound -- it fails on a deliberately-false ensures
410	// and kills every injected mutant -- only once the depth bound is raised to
411	// ~600).  Consequently the mutation kill score is 0 at the fixed bound: no
412	// sound, cheaper-to-check contract exists, because every mutant-distinguishing
413	// observation needs either the deep rotation path or a full predicate
414	// evaluation, both of which overrun depth 200.  The strong contract is kept as
415	// written rather than weakened to a contract that verifies non-vacuously but
416	// specifies less.
417	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
418	__CPROVER_assigns(__CPROVER_object_whole(board))
419	__CPROVER_ensures(__CPROVER_return_value ==
420	                  (NO_EMPTY && !ANY_H_PAIR && !ANY_V_PAIR))
421	__CPROVER_ensures(GE_UNCHANGED(0, 0) && GE_UNCHANGED(0, 1) &&
422	                  GE_UNCHANGED(0, 2) && GE_UNCHANGED(0, 3))
423	__CPROVER_ensures(GE_UNCHANGED(1, 0) && GE_UNCHANGED(1, 1) &&
424	                  GE_UNCHANGED(1, 2) && GE_UNCHANGED(1, 3))
425	__CPROVER_ensures(GE_UNCHANGED(2, 0) && GE_UNCHANGED(2, 1) &&
426	                  GE_UNCHANGED(2, 2) && GE_UNCHANGED(2, 3))
427	__CPROVER_ensures(GE_UNCHANGED(3, 0) && GE_UNCHANGED(3, 1) &&
428	                  GE_UNCHANGED(3, 2) && GE_UNCHANGED(3, 3))
429	{
430		bool ended = true;
431		if (countEmpty(board) > 0)
432			return false;
433		if (findPairDown(board))
434			return false;
435		rotateBoard(board);
436		if (findPairDown(board))
437			ended = false;
438		rotateBoard(board);
439		rotateBoard(board);
440		rotateBoard(board);
441		return ended;
442	}
443	
444	/* Helpers for specifying `addRandom`. Constant cell indices are used throughout
445	 * because CBMC's history variables (`__CPROVER_old`) do not support array
446	 * snapshots under a quantified index, so the 4x4 board is enumerated explicitly.
447	 *
448	 *  - CELL_UNCHANGED_OR_NEW(r,c): cell (r,c) either keeps its old value, or was
449	 *    empty (0) and now holds a freshly spawned tile (1 or 2).
450	 *  - CELL_CHANGED(r,c): 1 if cell (r,c) differs from its old value, else 0.
451	 *  - WAS_EMPTY(r,c): true iff cell (r,c) held 0 before the call. */
452	#define CELL_UNCHANGED_OR_NEW(r, c)                       \
453		(board[r][c] == __CPROVER_old(board[r][c]) ||         \
454		 (__CPROVER_old(board[r][c]) == 0 &&                  \
455		  (board[r][c] == 1 || board[r][c] == 2)))
456	#define CELL_CHANGED(r, c) (board[r][c] != __CPROVER_old(board[r][c]) ? 1 : 0)
457	#define WAS_EMPTY(r, c) (__CPROVER_old(board[r][c]) == 0)
458	
459	/* Number of board cells that changed value over the call. */
460	#define NUM_CHANGED                                                      \
461		(CELL_CHANGED(0, 0) + CELL_CHANGED(0, 1) + CELL_CHANGED(0, 2) +      \
462		 CELL_CHANGED(0, 3) + CELL_CHANGED(1, 0) + CELL_CHANGED(1, 1) +      \
463		 CELL_CHANGED(1, 2) + CELL_CHANGED(1, 3) + CELL_CHANGED(2, 0) +      \
464		 CELL_CHANGED(2, 1) + CELL_CHANGED(2, 2) + CELL_CHANGED(2, 3) +      \
465		 CELL_CHANGED(3, 0) + CELL_CHANGED(3, 1) + CELL_CHANGED(3, 2) +      \
466		 CELL_CHANGED(3, 3))
467	
468	/* True iff the board had at least one empty cell before the call. */
469	#define HAD_EMPTY                                                        \
470		(WAS_EMPTY(0, 0) || WAS_EMPTY(0, 1) || WAS_EMPTY(0, 2) ||            \
471		 WAS_EMPTY(0, 3) || WAS_EMPTY(1, 0) || WAS_EMPTY(1, 1) ||            \
472		 WAS_EMPTY(1, 2) || WAS_EMPTY(1, 3) || WAS_EMPTY(2, 0) ||            \
473		 WAS_EMPTY(2, 1) || WAS_EMPTY(2, 2) || WAS_EMPTY(2, 3) ||            \
474		 WAS_EMPTY(3, 0) || WAS_EMPTY(3, 1) || WAS_EMPTY(3, 2) ||            \
475		 WAS_EMPTY(3, 3))
476	
477	void addRandom(uint8_t board[SIZE][SIZE])
478	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
479	__CPROVER_assigns(__CPROVER_object_whole(board))
480	/* Every cell is either unchanged or a newly spawned tile in a formerly empty
481	 * cell -- in particular, no non-empty tile is ever overwritten or cleared. */
482	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 0))
483	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 1))
484	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 2))
485	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 3))
486	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 0))
487	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 1))
488	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 2))
489	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 3))
490	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 0))
491	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 1))
492	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 2))
493	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 3))
494	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 0))
495	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 1))
496	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 2))
497	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 3))
498	/* Exactly one tile is spawned when the board had room, and none otherwise. */
499	__CPROVER_ensures(NUM_CHANGED == (HAD_EMPTY ? 1 : 0))
500	{
501		static bool initialized = false;
502		uint8_t x, y;
503		uint8_t r, len = 0;
504		uint8_t n, list[SIZE * SIZE][2];
505	
506		if (!initialized)
507		{
508			srand(time(NULL));
509			initialized = true;
510		}
511	
512		for (x = 0; x < SIZE; x++)
513		{
514			for (y = 0; y < SIZE; y++)
515			{
516				if (board[x][y] == 0)
517				{
518					list[len][0] = x;
519					list[len][1] = y;
520					len++;
521				}
522			}
523		}
524	
525		if (len > 0)
526		{
527			r = rand() % len;
528			x = list[r][0];
529			y = list[r][1];
530			n = (rand() % 10) / 9 + 1;
531			board[x][y] = n;
532		}
533	}
534	
535	void initBoard(uint8_t board[SIZE][SIZE])
536	{
537		uint8_t x, y;
538		for (x = 0; x < SIZE; x++)
539		{
540			for (y = 0; y < SIZE; y++)
541			{
542				board[x][y] = 0;
543			}
544		}
545		addRandom(board);
546		addRandom(board);
547	}
548	
549	void setBufferedInput(bool enable)
550	{
551		static bool enabled = true;
552		static struct termios old;
553		struct termios new;
554	
555		if (enable && !enabled)
556		{
557			// restore the former settings
558			tcsetattr(STDIN_FILENO, TCSANOW, &old);
559			// set the new state
560			enabled = true;
561		}
562		else if (!enable && enabled)
563		{
564			// get the terminal settings for standard input
565			tcgetattr(STDIN_FILENO, &new);
566			// we want to keep the old setting to restore them at the end
567			old = new;
568			// disable canonical mode (buffered i/o) and local echo
569			new.c_lflag &= (~ICANON & ~ECHO);
570			// set the new settings immediately
571			tcsetattr(STDIN_FILENO, TCSANOW, &new);
572			// set the new state
573			enabled = false;
574		}
575	}
576	
577	bool testSucceed()
578	{
579		uint8_t array[SIZE];
580		// these are exponents with base 2 (1=2 2=4 3=8)
581		// data holds per line: 4x IN, 4x OUT, 1x POINTS
582		uint8_t data[] = {
583			0, 0, 0, 1, 1, 0, 0, 0, 0,
584			0, 0, 1, 1, 2, 0, 0, 0, 4,
585			0, 1, 0, 1, 2, 0, 0, 0, 4,
586			1, 0, 0, 1, 2, 0, 0, 0, 4,
587			1, 0, 1, 0, 2, 0, 0, 0, 4,
588			1, 1, 1, 0, 2, 1, 0, 0, 4,
589			1, 0, 1, 1, 2, 1, 0, 0, 4,
590			1, 1, 0, 1, 2, 1, 0, 0, 4,
591			1, 1, 1, 1, 2, 2, 0, 0, 8,
592			2, 2, 1, 1, 3, 2, 0, 0, 12,
593			1, 1, 2, 2, 2, 3, 0, 0, 12,
594			3, 0, 1, 1, 3, 2, 0, 0, 4,
595			2, 0, 1, 1, 2, 2, 0, 0, 4};
596		uint8_t *in, *out, *points;
597		uint8_t t, tests;
598		uint8_t i;
599		bool success = true;
600		uint32_t score;
601	
602		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
603		for (t = 0; t < tests; t++)
604		{
605			in = data + t * (2 * SIZE + 1);
606			out = in + SIZE;
607			points = in + 2 * SIZE;
608			for (i = 0; i < SIZE; i++)
609			{
610				array[i] = in[i];
611			}
612			score = 0;
613			slideArray(array, &score);
614			for (i = 0; i < SIZE; i++)
615			{
616				if (array[i] != out[i])
617				{
618					success = false;
619				}
620			}
621			if (score != *points)
622			{
623				success = false;
624			}
625			if (success == false)
626			{
627				for (i = 0; i < SIZE; i++)
628				{
629					printf("%u ", in[i]);
630				}
631				printf("=> ");
632				for (i = 0; i < SIZE; i++)
633				{
634					printf("%u ", array[i]);
635				}
636				printf("(%u points) expected ", score);
637				for (i = 0; i < SIZE; i++)
638				{
639					printf("%u ", in[i]);
640				}
641				printf("=> ");
642				for (i = 0; i < SIZE; i++)
643				{
644					printf("%u ", out[i]);
645				}
646				printf("(%u points)\n", *points);
647				break;
648			}
649		}
650		if (success)
651		{
652			printf("All %u tests executed successfully\n", tests);
653		}
654		return success;
655	}
656	
657	void signal_callback_handler(int signum)
658	{
659		printf("         TERMINATED         \n");
660		setBufferedInput(true);
661		// make cursor visible, reset all modes
662		printf("\033[?25h\033[m");
663		exit(signum);
664	}
665	
666	int main(int argc, char *argv[])
667	{
668		uint8_t board[SIZE][SIZE];
669		uint8_t scheme = 0;
670		uint32_t score = 0;
671		int c;
672		bool success;
673	
674		// handle the command line options
675		if (argc > 1)
676		{
677			if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0)
678			{
679				printf("Usage: 2048 [OPTION] | [MODE]\n");
680				printf("Play the game 2048 in the console\n\n");
681				printf("Options:\n");
682				printf("  -h,  --help       Show this help message.\n");
683				printf("  -v,  --version    Show version number.\n\n");
684				printf("Modes:\n");
685				printf("  bluered      Use a blue-to-red color scheme (requires 256-color terminal support).\n");
686				printf("  blackwhite   The black-to-white color scheme (requires 256-color terminal support).\n");
687				return EXIT_SUCCESS;
688			}
689			else if (strcmp(argv[1], "-v") == 0 || strcmp(argv[1], "--version") == 0)
690			{
691				printf("2048.c version %s\n", VERSION);
692				return EXIT_SUCCESS;
693			}
694			else if (strcmp(argv[1], "blackwhite") == 0)
695			{
696				scheme = 1;
697			}
698			else if (strcmp(argv[1], "bluered") == 0)
699			{
700				scheme = 2;
701			}
702			else if (strcmp(argv[1], "whiteblack") == 0)
703			{
704				scheme = 3;
705			}
706			else if (strcmp(argv[1], "test") == 0)
707			{
708				return testSucceed() ? EXIT_SUCCESS : EXIT_FAILURE;
709			}
710			else
711			{
712				printf("Invalid option: %s\n\nTry '%s --help' for more options.\n", argv[1], argv[0]);
713				return EXIT_FAILURE;
714			}
715		}
716	
717		// make cursor invisible, erase entire screen
718		printf("\033[?25l\033[2J");
719	
720		// register signal handler for when ctrl-c is pressed
721		signal(SIGINT, signal_callback_handler);
722	
723		initBoard(board);
724		setBufferedInput(false);
725		drawBoard(board, scheme, score);
726		while (true)
727		{
728			c = getchar();
729			if (c == EOF)
730			{
731				puts("\nError! Cannot read keyboard input!");
732				break;
733			}
734			switch (c)
735			{
736			case 52:  // '4' key
737			case 97:  // 'a' key
738			case 104: // 'h' key
739			case 68:  // left arrow
740				success = moveLeft(board, &score);
741				break;
742			case 54:  // '6' key
743			case 100: // 'd' key
744			case 108: // 'l' key
745			case 67:  // right arrow
746				success = moveRight(board, &score);
747				break;
748			case 56:  // '8' key
749			case 119: // 'w' key
750			case 107: // 'k' key
751			case 65:  // up arrow
752				success = moveUp(board, &score);
753				break;
754			case 50:  // '2' key
755			case 115: // 's' key
756			case 106: // 'j' key
757			case 66:  // down arrow
758				success = moveDown(board, &score);
759				break;
760			default:
761				success = false;
762			}
763			if (success)
764			{
765				drawBoard(board, scheme, score);
766				usleep(150 * 1000); // 150 ms
767				addRandom(board);
768				drawBoard(board, scheme, score);
769				if (gameEnded(board))
770				{
771					printf("         GAME OVER          \n");
772					break;
773				}
774			}
775			if (c == 'q')
776			{
777				printf("        QUIT? (y/n)         \n");
778				c = getchar();
779				if (c == 'y')
780				{
781					break;
782				}
783				drawBoard(board, scheme, score);
784			}
785			if (c == 'r')
786			{
787				printf("       RESTART? (y/n)       \n");
788				c = getchar();
789				if (c == 'y')
790				{
791					initBoard(board);
792					score = 0;
793				}
794				drawBoard(board, scheme, score);
795			}
796		}
797		setBufferedInput(true);
798	
799		// make cursor visible, reset all modes
800		printf("\033[?25h\033[m");
801	
802		return EXIT_SUCCESS;
803	}
